const projects = dv.pages('"Projects"')
    .where(p => p.status && p.status !== "완료")
    .sort(p => p.priority || "medium");

dv.table(
    ["Project", "Status", "Progress", "Due Date", "Actions"],
    projects.map(p => [
        `[[${p.file.name}|${p.title || p.file.name}]]`,
        `${getStatusEmoji(p.status)} ${p.status}`,
        `${p.progress || 0}% ${generateProgressBar(p.progress || 0)}`,
        p.due ? `⏰ ${p.due}` : "No due date",
        `[[${p.file.name}#^button-update|Update]]`
    ])
);

function getStatusEmoji(status) {
    const emojiMap = {
        "시작": "🟢",
        "진행중": "🟡", 
        "검토": "🔵",
        "보류": "🟠",
        "완료": "✅"
    };
    return emojiMap[status] || "⚪";
}

function generateProgressBar(progress) {
    const total = 10;
    const filled = Math.round((progress / 100) * total);
    return "█".repeat(filled) + "░".repeat(total - filled);
}
```

